{
  "title": "Python for Educators: From Beginner to Expert",
  "description": "This course is designed for educators in the ASEAN region who are beginners in Python and aspire to become experts. The course emphasizes text-first explanations and practical activities suitable for low-bandwidth environments.",
  "modules": [
    {
      "id": "module_1",
      "title": "Introduction to Python",
      "description": "Learn the basics of Python, including syntax, data types, and control structures. Engage in hands-on activities to reinforce concepts.",
      "facilitation_tips": "Encourage learners to write simple scripts to solve everyday problems. Use text-based resources and printed materials to support learning."
    },
    {
      "id": "module_2",
      "title": "Working with Data",
      "description": "Explore how to handle data in Python using lists, dictionaries, and basic file operations. Activities will focus on data manipulation and analysis.",
      "facilitation_tips": "Incorporate real-life data examples relevant to the learners' context. Facilitate group discussions on data interpretation."
    },
    {
      "id": "module_3",
      "title": "Introduction to Python Libraries",
      "description": "Get introduced to essential Python libraries such as NumPy and Pandas. Learn how to install and use these libraries for data analysis.",
      "facilitation_tips": "Provide step-by-step guides for library installation. Use text-based tutorials to demonstrate library functionalities."
    },
    {
      "id": "module_4",
      "title": "Building Projects with Python",
      "description": "Apply your knowledge by creating simple projects that demonstrate your skills. Projects will focus on practical applications relevant to education.",
      "facilitation_tips": "Encourage collaboration among learners to share ideas and solutions. Provide structured project templates to guide their work."
    }
  ]
}
